var EE_AI_DRAFTS={locations:{name:"Brittlewood Track",aliases:["the Brittlewood","salt track"],kind:"Forest",summary:"A frostbitten stand of spruce north of the Vraska road. Locals say letters left under the third bridge stay until someone needs them.",description:"Brittlewood is the kind of place names move through more than people. The track is a thin road of split logs over winter mud, hemmed by black spruce that have learnt to lean against the wind. In daylight the forest reads as quiet; after dusk it begins to listen.",danger:"watched",history:"Once Vey hunting-ground; ceded to the Reach in the Salt Treaty.",tags:["winter","north-road","liminal"]},items:{name:"Vraska Lantern",aliases:["pass-lantern","Brec's lantern"],itemType:"Tool",rarity:"Uncommon",summary:"A heavy iron-and-glass lantern Brec carries through the pass. Burns long, never cleanly.",description:"Iron cage, four glass panels, brass handle scoured to a dull gold. Smells of fish-oil and pitch even cold. The wick is too long, deliberately — Brec uses the smoke as a tracking sign.",modifiers:[{target:"Perception",delta:+1,note:"Far sight at night"}],affixes:[{name:"Smoke-tracker",note:"Leaves a readable trail for half a mile in still air"}],slot:"Off Hand"},classes:{name:"Glass-reader",category:"Scholar",role:"Scholar",summary:"Court archivists trained to read the Glass Court's layered ledgers and call out the lines no one wanted read.",description:"Glass-readers are made, not born. Twelve years in the Glass Court archives, three more on the rotation between Hess and Vey holds. Their badge of office is a single etched lens, worn on a chain.",defaultStats:[{name:"Cunning",value:14,min:1,max:20},{name:"Standing",value:11,min:1,max:20}]},races:{name:"Glass-touched",category:"Hybrid",summary:"Hess-born marked by the Court's glass-ritual; one eye is paler than the other, and they read written word better than the spoken.",traits:["Letter-trained","Slow to warm","Glass-eye"],description:"A small population (perhaps three in a hundred Hess-born) whose change is mild but visible. They tend toward archive work and toward unhappy marriages with anyone who does not know their letters."},stats:{name:"Grief",summary:"A scale value tracking the weight a character carries from losses inflicted by the manuscript. Affects available actions in private scenes.",valueType:"scale",extractionRules:[{phrase:"could not bring herself to",treatedAs:"Qualitative grief +1",kind:"qual",review:true,effect:"increase",confidence:"orange"},{phrase:"did not look at the chair",treatedAs:"Qualitative grief +1",kind:"qual",review:true,effect:"increase",confidence:"orange"},{phrase:"wept openly",treatedAs:"Qualitative grief +2",kind:"qual",review:true,effect:"increase",confidence:"green"}]},quests:{title:"The Salt-bitten Cloak",questType:"Mystery",status:"Active",summary:"Whose cloak did Brec find on the Vraska road? The garment fits no one in Pale Reach Hold.",goal:"Identify the cloak's owner before the next Court audience.",steps:[{title:"Find the cloak",chapter:5,location:"Vraska Pass"},{title:"Wash and inspect",chapter:5},{title:"Match against ledger",chapter:6},{title:"Confront the owner",chapter:7}]},events:{title:"Brec's Letter Arrives",eventType:"Reveal",summary:"Captain Brec's sealed letter arrives at Pale Reach Hold three nights before the Court audience.",cause:"Brec sealed the letter at Brittlewood after losing the Hess Letter-key.",immediateOutcome:"Aelinor does not sleep for three nights and packs the Auger for the Court.",longTermConsequence:"Sets the chain that ends in the Vraska break."},skills:{name:"Salt-walker",skillType:"passive",summary:"A learned step that lets the carrier cross salted causeways without harm.",description:"Not a spell, not a gift. The body comes to know which planks of a causeway the salt loves and which it ignores, and after a winter the feet move on their own.",effects:[{trigger:"On entering causeway",effect:"Ignore terrain penalty"}],requirements:["At least one winter spent on the Reach."]}};Object.assign(window,{ENTITY_EDITOR_CONFIGS,EE_AI_DRAFTS,EE_LOCATION_TYPES,EE_ITEM_TYPES,EE_EQUIPMENT_SLOTS,EE_RARITY,EE_CLASS_CATEGORIES,EE_RACE_CATEGORIES,EE_STAT_VALUE_TYPES,EE_QUEST_TYPES,EE_QUEST_STATUSES,EE_EVENT_TYPES,EE_SKILL_TYPES,EE_RULE_MATCH_TYPES,EE_RULE_EFFECT_TYPES,EE_CONFIDENCE_BANDS});// ==== file: entity-editor-configs-extended.jsx ====
