var WR_MANUSCRIPT=[{id:"p1",author:"em",attr:"EM",parts:[{text:"The light over "},{mark:"locations",id:"e-pale-reach",text:"Pale Reach"},{text:" was the colour of cooled tin when "},{mark:"cast",id:"e-aelinor",text:"Aelinor Vey"},{text:" came through the stockade gate. Snow had been falling all morning, and the wind off the salt flats turned each flake into a small, deliberate cut."}]},{id:"p2",author:"em",attr:"EM",parts:[{text:"She carried the "},{mark:"items",id:"e-auger",text:"Auger of Hess"},{text:" in a felt-lined case slung across her back, and even wrapped, even quiet, it pressed against her like a second pulse. "},{cmt:"1",text:"She had not slept since Brec's letter"},{text:", and three nights of refusing the dreams had given her hands a fine, undignified tremor."}]},{id:"p3",author:"em",attr:"EM",parts:[{text:"\"You're the wrong shape for this weather,\" said "},{mark:"cast",id:"e-brec",text:"Captain Brec"},{text:" from the watchhouse step. He looked the same as he had four winters ago, except for the way the cold had settled into his face — not as colour but as architecture."}]},{sceneBreak:true},{id:"p4",author:"ann",attr:"AN",parts:[{text:"Inside, the watchhouse smelled of pitch and coriander, and the brazier had been pulled close to the lieutenant's table. "},{mark:"factions",id:"e-greycoats",text:"The Grey Coats"},{text:" had left only the one banner — a small concession Aelinor noticed because Brec had told her, once, that they would never lower it."}]},{id:"p5",author:"em",attr:"EM",parts:[{text:"\"It's not a courtesy,\" he said, pouring her something dark from a clay carafe. \"It's an apology. The "},{mark:"events",id:"e-augerwake",text:"Auger Wake"},{text:" came through here last week. Took two of mine, and a goat. We're not pretending anymore.\""}]},{id:"p6",author:"em",attr:"EM",parts:[{text:"She set the case on the table. The wood under it gave the smallest, indignant sigh. \"Then you'll want to see what "},{mark:"cast",id:"e-saren",text:"Saren of Hess"},{text:" sent me to bring.\""}]},{id:"p7",author:"ai",attr:"LW",parts:[{text:"Brec did not look at the case. He looked, instead, at the door, and the wind beyond it. \"Tell me first,\" he said, \"whether the road through "},{mark:"atlas",id:"e-vraska",text:"the Vraska Pass"},{text:" is still walkable. I have a child to send south, and I would prefer to send her alive.\""}]}];// Margin notes (left column)
